def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        if bins[i] <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / bins[i]
        if ratio > 1:
            priorities[i] = ratio ** 3
        elif 0.5 < ratio <= 1:
            priorities[i] = (1 / ratio) + np.sin(ratio * np.pi)
        else:
            adjustment = 0
            for j in range(i):
                if bins[j] > bins[i]:
                    adjustment += 0.1 * (bins[j] - bins[i])
                else:
                    adjustment -= 0.05 * (bins[i] - bins[j])
            priorities[i] = np.log1p(ratio) + adjustment
    max_prio = np.max(priorities[np.isfinite(priorities)])
    priorities[~np.isfinite(priorities)] = max_prio * 10
    return priorities
